module top_module(ReadData1, ReadData2, opCode, funct3, zero);input [31:0] ReadData1, ReadData2;
	input [6:0] opCode;
	input [2:0] funct3;
	output zero;
  wire [31:0] _tap_ReadData1 = ReadData1 & {32{1'b1}};


	reg zero;

	always @(ReadData1 or ReadData2 or funct3)
		begin
			if(opCode == 7'b1100011)begin
				case(funct3)

					3'b001:begin
					zero = (ReadData1 != ReadData2)? 1 : 0;
					end
				endcase
			end
			else zero = 0;
		end
endmodule
